1	/**
2	 * The Scriptorium — core logic.
3	 *
4	 * Manages the codex registry (bare clones), draft binding lifecycle
5	 * (worktrees), and sealing (ff-only merge or rebase+ff). All git
6	 * operations go through the git helper for safety.
7	 *
8	 * Draft tracking is in-memory — drafts are reconstructed from
9	 * filesystem state at startup and maintained in memory during the
10	 * process lifetime.
11	 *
12	 * See: docs/architecture/apparatus/scriptorium.md
13	 */
14	
15	import fs from 'node:fs';
16	import path from 'node:path';
17	
18	import { guild, generateId } from '@shardworks/nexus-core';
19	
20	import { git, resolveDefaultBranch, resolveRef, commitsAhead, GitError } from './git.ts';
21	
22	import type {
23	  CodexRecord,
24	  CodexDetail,
25	  DraftRecord,
26	  OpenDraftRequest,
27	  AbandonDraftRequest,
28	  SealRequest,
29	  SealResult,
30	  PushRequest,
31	  CodexesConfig,
32	  CodexConfigEntry,
33	  ScriptoriumApi,
34	} from './types.ts';
35	
36	// ── Internal state ──────────────────────────────────────────────────
37	
38	interface CodexState {
39	  name: string
40	  remoteUrl: string
41	  cloneStatus: 'ready' | 'cloning' | 'error'
42	  lastFetched: string | null
43	  /** Promise that resolves when the bare clone is ready (for background clones). */
44	  clonePromise?: Promise<void>
45	}
46	
47	// ── Core class ──────────────────────────────────────────────────────
48	
49	export class ScriptoriumCore {
50	  private codexes = new Map<string, CodexState>();
51	  private drafts = new Map<string, DraftRecord>(); // keyed by `${codexName}/${branch}`
52	
53	  private maxMergeRetries: number = 3;
54	  private draftRoot: string = '.nexus/worktrees';
55	
56	  // ── Paths ───────────────────────────────────────────────────────
57	
58	  private get home(): string {
59	    return guild().home;
60	  }
61	
62	  private codexesDir(): string {
63	    return path.join(this.home, '.nexus', 'codexes');
64	  }
65	
66	  private bareClonePath(name: string): string {
67	    return path.join(this.codexesDir(), `${name}.git`);
68	  }
69	
70	  private draftWorktreePath(codexName: string, branch: string): string {
71	    return path.join(this.home, this.draftRoot, codexName, branch);
72	  }
73	
74	  // ── Startup ─────────────────────────────────────────────────────
75	
76	  start(): void {
77	    const config = guild().config<CodexesConfig>('codexes');
78	
79	    // Apply settings
80	    this.maxMergeRetries = config.settings?.maxMergeRetries ?? 3;
81	    this.draftRoot = config.settings?.draftRoot ?? '.nexus/worktrees';
82	
83	    // Ensure infrastructure directories exist
84	    fs.mkdirSync(this.codexesDir(), { recursive: true });
85	
86	    // Load registered codexes from config
87	    const registered = config.registered ?? {};
88	    for (const [name, entry] of Object.entries(registered)) {
89	      this.loadCodex(name, entry);
90	    }
91	
92	    // Reconcile drafts from filesystem
93	    this.reconcileDrafts();
94	  }
95	
96	  /**
97	   * Load a codex from config. Checks for existing bare clone;
98	   * initiates background clone if missing.
99	   */
100	  private loadCodex(name: string, entry: CodexConfigEntry): void {
101	    const clonePath = this.bareClonePath(name);
102	    const exists = fs.existsSync(clonePath);
103	
104	    const state: CodexState = {
105	      name,
106	      remoteUrl: entry.remoteUrl,
107	      cloneStatus: exists ? 'ready' : 'cloning',
108	      lastFetched: null,
109	    };
110	
111	    if (!exists) {
112	      // Background clone — doesn't block startup
113	      state.clonePromise = this.performClone(name, entry.remoteUrl)
114	        .then(() => { state.cloneStatus = 'ready'; })
115	        .catch((err) => {
116	          state.cloneStatus = 'error';
117	          console.warn(`[scriptorium] Background clone of "${name}" failed: ${err instanceof Error ? err.message : err}`);
118	        });
119	    }
120	
121	    this.codexes.set(name, state);
122	  }
123	
124	  /**
125	   * Reconcile in-memory draft tracking with filesystem state.
126	   * Scans the worktree directories and rebuilds the draft map.
127	   */
128	  private reconcileDrafts(): void {
129	    const worktreeRoot = path.join(this.home, this.draftRoot);
130	    if (!fs.existsSync(worktreeRoot)) return;
131	
132	    for (const codexDir of fs.readdirSync(worktreeRoot, { withFileTypes: true })) {
133	      if (!codexDir.isDirectory()) continue;
134	      const codexName = codexDir.name;
135	
136	      // Only reconcile drafts for known codexes
137	      if (!this.codexes.has(codexName)) continue;
138	
139	      const codexWorktreeDir = path.join(worktreeRoot, codexName);
140	      for (const draftDir of fs.readdirSync(codexWorktreeDir, { withFileTypes: true })) {
141	        if (!draftDir.isDirectory()) continue;
142	        const branch = draftDir.name;
143	        const draftPath = path.join(codexWorktreeDir, branch);
144	
145	        // Verify it's actually a git worktree (has .git file)
146	        if (!fs.existsSync(path.join(draftPath, '.git'))) continue;
147	
148	        const key = `${codexName}/${branch}`;
149	        if (!this.drafts.has(key)) {
150	          this.drafts.set(key, {
151	            id: generateId('draft', 4),
152	            codexName,
153	            branch,
154	            path: draftPath,
155	            createdAt: new Date().toISOString(), // approximate — we don't know the real time
156	          });
157	        }
158	      }
159	    }
160	  }
161	
162	  // ── Clone readiness ─────────────────────────────────────────────
163	
164	  /**
165	   * Ensure a codex's bare clone is ready. Blocks if a background
166	   * clone is in progress. Throws if the codex is unknown or clone failed.
167	   */
168	  private async ensureReady(name: string): Promise<CodexState> {
169	    const state = this.codexes.get(name);
170	    if (!state) {
171	      throw new Error(`Codex "${name}" is not registered. Use codex-add to register it.`);
172	    }
173	
174	    if (state.clonePromise) {
175	      await state.clonePromise;
176	      state.clonePromise = undefined;
177	    }
178	
179	    if (state.cloneStatus === 'error') {
180	      throw new Error(
181	        `Codex "${name}" bare clone failed. Remove and re-add the codex, or check the remote URL.`,
182	      );
183	    }
184	
185	    return state;
186	  }
187	
188	  // ── Git operations ──────────────────────────────────────────────
189	
190	  private async performClone(name: string, remoteUrl: string): Promise<void> {
191	    const clonePath = this.bareClonePath(name);
192	    fs.mkdirSync(path.dirname(clonePath), { recursive: true });
193	    await git(['clone', '--bare', remoteUrl, clonePath]);
194	  }
195	
196	  /**
197	   * Advance refs/heads/<branch> to the remote's position if the remote is
198	   * strictly ahead of the local sealed binding.
199	   *
200	   * This handles commits pushed to the remote outside the Scriptorium:
201	   * if the remote has advanced past the local sealed binding, sealing must
202	   * rebase the draft onto the remote position — not the stale local one.
203	   *
204	   * If the local sealed binding is already ahead of (or equal to) the remote
205	   * (e.g. contains unpushed seals from contention scenarios), it is kept.
206	   */
207	  private async advanceToRemote(codexName: string, branch: string): Promise<void> {
208	    const clonePath = this.bareClonePath(codexName);
209	    let remoteRef: string;
210	    try {
211	      remoteRef = await resolveRef(clonePath, `refs/remotes/origin/${branch}`);
212	    } catch {
213	      return; // No remote tracking ref (branch may not exist on remote yet)
214	    }
215	    const localRef = await resolveRef(clonePath, branch);
216	    if (remoteRef === localRef) return;
217	
218	    const { stdout: mergeBase } = await git(
219	      ['merge-base', localRef, remoteRef],
220	      clonePath,
221	    );
222	    if (mergeBase === localRef) {
223	      // Local is an ancestor of remote → remote is ahead → advance local
224	      await git(['update-ref', `refs/heads/${branch}`, remoteRef], clonePath);
225	    }
226	    // If local is ahead of or diverged from remote: keep the local sealed binding
227	  }
228	
229	  private async performFetch(name: string): Promise<void> {
230	    const clonePath = this.bareClonePath(name);
231	    // Explicit refspec is required: git clone --bare does not configure a
232	    // fetch refspec, so plain `git fetch origin` only updates FETCH_HEAD and
233	    // leaves refs/heads/* stale.
234	    //
235	    // We fetch into refs/remotes/origin/* rather than refs/heads/* for two
236	    // reasons:
237	    //   1. It avoids force-overwriting local draft branches (which live in
238	    //      refs/heads/* but do not exist on the remote).
239	    //   2. It separates the "remote position" (refs/remotes/origin/*) from
240	    //      the "local sealed binding" (refs/heads/*), letting seal() advance
241	    //      refs/heads/* only when the remote is strictly ahead.
242	    await git(['fetch', '--prune', 'origin', '+refs/heads/*:refs/remotes/origin/*'], clonePath);
243	
244	    const state = this.codexes.get(name);
245	    if (state) {
246	      state.lastFetched = new Date().toISOString();
247	    }
248	  }
249	
250	  // ── API Implementation ────────────────────────────────────────
251	
252	  createApi(): ScriptoriumApi {
253	    return {
254	      add: (name, remoteUrl) => this.add(name, remoteUrl),
255	      list: () => this.list(),
256	      show: (name) => this.show(name),
257	      remove: (name) => this.remove(name),
258	      fetch: (name) => this.fetchCodex(name),
259	      push: (request) => this.push(request),
260	      openDraft: (request) => this.openDraft(request),
261	      listDrafts: (codexName?) => this.listDrafts(codexName),
262	      abandonDraft: (request) => this.abandonDraft(request),
263	      seal: (request) => this.seal(request),
264	    };
265	  }
266	
267	  // ── Codex Registry ──────────────────────────────────────────────
268	
269	  async add(name: string, remoteUrl: string): Promise<CodexRecord> {
270	    if (this.codexes.has(name)) {
271	      throw new Error(`Codex "${name}" is already registered.`);
272	    }
273	
274	    // Clone bare repo (blocking)
275	    const state: CodexState = {
276	      name,
277	      remoteUrl,
278	      cloneStatus: 'cloning',
279	      lastFetched: null,
280	    };
281	    this.codexes.set(name, state);
282	
283	    try {
284	      await this.performClone(name, remoteUrl);
285	      state.cloneStatus = 'ready';
286	    } catch (err) {
287	      state.cloneStatus = 'error';
288	      this.codexes.delete(name);
289	      throw new Error(
290	        `Failed to clone "${remoteUrl}" for codex "${name}": ${err instanceof Error ? err.message : err}`,
291	      );
292	    }
293	
294	    // Persist to guild.json
295	    const config = guild().config<CodexesConfig>('codexes');
296	    const registered = config.registered ?? {};
297	    registered[name] = { remoteUrl };
298	    guild().writeConfig('codexes', { ...config, registered });
299	
300	    return this.toCodexRecord(state);
301	  }
302	
303	  async list(): Promise<CodexRecord[]> {
304	    const records: CodexRecord[] = [];
305	    for (const state of this.codexes.values()) {
306	      records.push(this.toCodexRecord(state));
307	    }
308	    return records;
309	  }
310	
311	  async show(name: string): Promise<CodexDetail> {
312	    const state = await this.ensureReady(name);
313	    const clonePath = this.bareClonePath(name);
314	    const defaultBranch = await resolveDefaultBranch(clonePath);
315	    const drafts = this.draftsForCodex(name);
316	
317	    return {
318	      name: state.name,
319	      remoteUrl: state.remoteUrl,
320	      cloneStatus: state.cloneStatus,
321	      activeDrafts: drafts.length,
322	      defaultBranch,
323	      lastFetched: state.lastFetched,
324	      drafts,
325	    };
326	  }
327	
328	  async remove(name: string): Promise<void> {
329	    const state = this.codexes.get(name);
330	    if (!state) {
331	      throw new Error(`Codex "${name}" is not registered.`);
332	    }
333	
334	    // Abandon all drafts for this codex
335	    const drafts = this.draftsForCodex(name);
336	    for (const draft of drafts) {
337	      await this.abandonDraft({ codexName: name, branch: draft.branch, force: true });
338	    }
339	
340	    // Remove bare clone
341	    const clonePath = this.bareClonePath(name);
342	    if (fs.existsSync(clonePath)) {
343	      fs.rmSync(clonePath, { recursive: true, force: true });
344	    }
345	
346	    // Remove from in-memory state
347	    this.codexes.delete(name);
348	
349	    // Remove from guild.json
350	    const config = guild().config<CodexesConfig>('codexes');
351	    const registered = { ...(config.registered ?? {}) };
352	    delete registered[name];
353	    guild().writeConfig('codexes', { ...config, registered });
354	  }
355	
356	  async fetchCodex(name: string): Promise<void> {
357	    await this.ensureReady(name);
358	    await this.performFetch(name);
359	  }
360	
361	  async push(request: PushRequest): Promise<void> {
362	    const state = await this.ensureReady(request.codexName);
363	    const clonePath = this.bareClonePath(state.name);
364	    const branch = request.branch ?? await resolveDefaultBranch(clonePath);
365	
366	    await git(['push', 'origin', branch], clonePath);
367	  }
368	
369	  // ── Draft Binding Lifecycle ─────────────────────────────────────
370	
371	  async openDraft(request: OpenDraftRequest): Promise<DraftRecord> {
372	    const state = await this.ensureReady(request.codexName);
373	    const clonePath = this.bareClonePath(state.name);
374	
375	    // Fetch before branching for freshness
376	    await this.performFetch(state.name);
377	
378	    const branch = request.branch ?? generateId('draft', 4);
379	    const key = `${request.codexName}/${branch}`;
380	
381	    // Reject if draft already exists
382	    if (this.drafts.has(key)) {
383	      throw new Error(
384	        `Draft with branch "${branch}" already exists for codex "${request.codexName}". ` +
385	        `Choose a different branch name or abandon the existing draft.`,
386	      );
387	    }
388	
389	    const defaultBranch = await resolveDefaultBranch(clonePath);
390	    const startPoint = request.startPoint ?? defaultBranch;
391	
392	    // Advance the start-point branch to the remote position if the remote
393	    // has moved ahead. Ensures the draft branches from the latest state.
394	    await this.advanceToRemote(state.name, startPoint);
395	
396	    const worktreePath = this.draftWorktreePath(request.codexName, branch);
397	    fs.mkdirSync(path.dirname(worktreePath), { recursive: true });
398	
399	    // Create worktree with new branch from start point
400	    await git(
401	      ['worktree', 'add', worktreePath, '-b', branch, startPoint],
402	      clonePath,
403	    );
404	
405	    const draft: DraftRecord = {
406	      id: generateId('draft', 4),
407	      codexName: request.codexName,
408	      branch,
409	      path: worktreePath,
410	      createdAt: new Date().toISOString(),
411	      associatedWith: request.associatedWith,
412	    };
413	
414	    this.drafts.set(key, draft);
415	    return draft;
416	  }
417	
418	  async listDrafts(codexName?: string): Promise<DraftRecord[]> {
419	    if (codexName) {
420	      return this.draftsForCodex(codexName);
421	    }
422	    return [...this.drafts.values()];
423	  }
424	
425	  async abandonDraft(request: AbandonDraftRequest): Promise<void> {
426	    const key = `${request.codexName}/${request.branch}`;
427	    const draft = this.drafts.get(key);
428	
429	    if (!draft) {
430	      throw new Error(
431	        `No active draft with branch "${request.branch}" for codex "${request.codexName}".`,
432	      );
433	    }
434	
435	    // Check for unsealed inscriptions (commits ahead of the sealed binding)
436	    if (!request.force) {
437	      const state = await this.ensureReady(request.codexName);
438	      const clonePath = this.bareClonePath(state.name);
439	
440	      try {
441	        const defaultBranch = await resolveDefaultBranch(clonePath);
442	        const ahead = await commitsAhead(clonePath, request.branch, defaultBranch);
443	
444	        if (ahead > 0) {
445	          throw new Error(
446	            `Draft "${request.branch}" has ${ahead} unsealed inscription(s). ` +
447	            `Use force: true to abandon anyway, or seal the draft first.`,
448	          );
449	        }
450	      } catch (err) {
451	        // If the branch doesn't exist in the bare clone (already cleaned up),
452	        // that's fine — proceed with cleanup
453	        if (err instanceof GitError && err.stderr.includes('unknown revision')) {
454	          // Branch already gone — proceed with cleanup
455	        } else if (err instanceof Error && err.message.includes('unsealed inscription')) {
456	          throw err;
457	        }
458	        // Other git errors during the check are non-fatal — proceed with cleanup
459	      }
460	    }
461	
462	    // Remove worktree
463	    const clonePath = this.bareClonePath(request.codexName);
464	    try {
465	      await git(['worktree', 'remove', '--force', draft.path], clonePath);
466	    } catch {
467	      // If worktree removal fails (e.g. already gone), try manual cleanup
468	      if (fs.existsSync(draft.path)) {
469	        fs.rmSync(draft.path, { recursive: true, force: true });
470	      }
471	      // Prune stale worktree references
472	      try {
473	        await git(['worktree', 'prune'], clonePath);
474	      } catch { /* best effort */ }
475	    }
476	
477	    // Delete the branch from the bare clone
478	    try {
479	      await git(['branch', '-D', request.branch], clonePath);
480	    } catch {
481	      // Branch may already be gone — that's fine
482	    }
483	
484	    // Remove from in-memory tracking
485	    this.drafts.delete(key);
486	  }
487	
488	  async seal(request: SealRequest): Promise<SealResult> {
489	    const state = await this.ensureReady(request.codexName);
490	    const clonePath = this.bareClonePath(state.name);
491	    const maxRetries = request.maxRetries ?? this.maxMergeRetries;
492	
493	    const defaultBranch = await resolveDefaultBranch(clonePath);
494	    const targetBranch = request.targetBranch ?? defaultBranch;
495	
496	    let strategy: 'fast-forward' | 'rebase' = 'fast-forward';
497	    let retries = 0;
498	
499	    // Fetch before sealing for freshness
500	    await this.performFetch(state.name);
501	
502	    // Advance the local sealed binding to the remote position if the remote
503	    // has moved ahead (e.g. commits pushed outside the Scriptorium).
504	    // This ensures seal compares against the latest remote ref, not a
505	    // potentially stale local one — preventing push failures.
506	    await this.advanceToRemote(state.name, targetBranch);
507	
508	    // Attempt ff-only merge, with rebase retry loop
509	    while (retries <= maxRetries) {
510	      try {
511	        // Try fast-forward merge: update the target branch ref to point at the source
512	        // In a bare repo, we use `git merge --ff-only` with the branch checked out,
513	        // but bare repos don't have a checkout. Instead, we verify ancestry and
514	        // update the ref directly.
515	        const targetRef = await resolveRef(clonePath, targetBranch);
516	        const sourceRef = await resolveRef(clonePath, request.sourceBranch);
517	
518	        // Check if source is already at target (nothing to seal)
519	        if (targetRef === sourceRef) {
520	          // Push before abandoning draft — if push fails the draft survives for inspection
521	          try {
522	            await git(['push', 'origin', targetBranch], clonePath);
523	          } catch (pushErr) {
524	            throw new Error(
525	              `Push failed after successful seal: ${pushErr instanceof Error ? pushErr.message : pushErr}`,
526	            );
527	          }
528	
529	          // Clean up draft unless keepDraft
530	          if (!request.keepDraft) {
531	            await this.abandonDraft({
532	              codexName: request.codexName,
533	              branch: request.sourceBranch,
534	              force: true,
535	            });
536	          }
537	          return { success: true, strategy, retries, sealedCommit: targetRef, inscriptionsSealed: 0 };
538	        }
539	
540	        // Check if target is an ancestor of source (ff is possible)
541	        const { stdout: mergeBase } = await git(
542	          ['merge-base', targetBranch, request.sourceBranch],
543	          clonePath,
544	        );
545	
546	        if (mergeBase === targetRef) {
547	          // Fast-forward is possible — count and incorporate inscriptions
548	          const inscriptionsSealed = await commitsAhead(
549	            clonePath,
550	            request.sourceBranch,
551	            targetBranch,
552	          );
553	
554	          await git(
555	            ['update-ref', `refs/heads/${targetBranch}`, sourceRef],
556	            clonePath,
557	          );
558	
559	          // Push before abandoning draft — if push fails the draft survives for inspection
560	          try {
561	            await git(['push', 'origin', targetBranch], clonePath);
562	          } catch (pushErr) {
563	            throw new Error(
564	              `Push failed after successful seal: ${pushErr instanceof Error ? pushErr.message : pushErr}`,
565	            );
566	          }
567	
568	          // Clean up draft unless keepDraft
569	          if (!request.keepDraft) {
570	            await this.abandonDraft({
571	              codexName: request.codexName,
572	              branch: request.sourceBranch,
573	              force: true,
574	            });
575	          }
576	
577	          return { success: true, strategy, retries, sealedCommit: sourceRef, inscriptionsSealed };
578	        }
579	
580	        // FF not possible — rebase the source branch onto the target
581	        strategy = 'rebase';
582	
583	        // Rebase needs a worktree (can't rebase in a bare repo).
584	        // Use the draft's existing worktree.
585	        const key = `${request.codexName}/${request.sourceBranch}`;
586	        const draft = this.drafts.get(key);
587	        if (!draft) {
588	          throw new Error(
589	            `Cannot rebase: no active draft for branch "${request.sourceBranch}". ` +
590	            `The draft worktree is needed for rebase operations.`,
591	          );
592	        }
593	
594	        try {
595	          await git(['rebase', targetBranch], draft.path);
596	        } catch (err) {
597	          // Rebase conflict — abort and fail
598	          try {
599	            await git(['rebase', '--abort'], draft.path);
600	          } catch { /* best effort */ }
601	
602	          throw new Error(
603	            `Sealing seized: rebase of "${request.sourceBranch}" onto "${targetBranch}" ` +
604	            `produced conflicts. Manual reconciliation is needed.`,
605	          );
606	        }
607	
608	        // Rebase succeeded — re-fetch and retry the ff merge
609	        retries++;
610	        await this.performFetch(state.name);
611	        continue;
612	      } catch (err) {
613	        if (err instanceof Error && err.message.includes('Sealing seized')) {
614	          throw err;
615	        }
616	        if (err instanceof Error && err.message.includes('Cannot rebase')) {
617	          throw err;
618	        }
619	        // Unexpected error — don't retry
620	        throw err;
621	      }
622	    }
623	
624	    throw new Error(
625	      `Sealing failed after ${maxRetries} retries. Codex "${request.codexName}", ` +
626	      `branch "${request.sourceBranch}" → "${targetBranch}".`,
627	    );
628	  }
629	
630	  // ── Helpers ───────────────────────────────────────────────────────
631	
632	  private draftsForCodex(codexName: string): DraftRecord[] {
633	    return [...this.drafts.values()].filter((d) => d.codexName === codexName);
634	  }
635	
636	  private toCodexRecord(state: CodexState): CodexRecord {
637	    return {
638	      name: state.name,
639	      remoteUrl: state.remoteUrl,
640	      cloneStatus: state.cloneStatus,
641	      activeDrafts: this.draftsForCodex(state.name).length,
642	    };
643	  }
644	}
